css:
.kpi-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 20px; }
.kpi-card {
  background: var(--bg-secondary); border: 1px solid var(--border);
  border-radius: 10px; padding: 16px;
  opacity: 0; transform: translateY(8px);
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}
.kpi-card.visible { opacity: 1; transform: translateY(0); }
.kpi-card .kpi-label {
  font-size: 11px; color: var(--text-muted); text-transform: uppercase;
  letter-spacing: 0.04em; margin-bottom: 6px;
}
.kpi-card .kpi-value { font-size: 26px; font-weight: 700; color: var(--heading); line-height: 1.1; }
.kpi-card .kpi-sub { font-size: 11px; margin-top: 4px; }
.kpi-card.highlight { border-color: var(--accent); background: var(--ring); }
.kpi-card.highlight .kpi-value { color: var(--accent-lt); }

.timeline { position: relative; padding-left: 24px; }
.timeline::before {
  content: ''; position: absolute; left: 5px; top: 4px; bottom: 4px;
  width: 2px; background: var(--border);
}
.tl-phase {
  position: relative; padding: 0 0 20px 20px;
  opacity: 0; transform: translateX(-10px);
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}
.tl-phase.visible { opacity: 1; transform: translateX(0); }
.tl-phase.dimmed { opacity: 0.2; }
.tl-phase::before {
  content: ''; position: absolute; left: -23px; top: 5px;
  width: 10px; height: 10px; border-radius: 50%;
  background: var(--bg); border: 2px solid var(--border);
  transition: all 0.3s; z-index: 1;
}
.tl-phase.active::before {
  border-color: var(--link); background: var(--accent);
  box-shadow: 0 0 10px var(--glow);
}
.tl-phase.complete::before { border-color: var(--green); background: var(--green); }
.tl-phase.milestone::before { border-radius: 2px; transform: rotate(45deg); }
.tl-dates { font-size: 10px; color: var(--text-muted); margin-bottom: 2px; }
.tl-phase.active .tl-dates { color: var(--link); }
.tl-name { font-size: 13px; font-weight: 600; color: var(--heading); margin-bottom: 2px; }
.tl-desc { font-size: 11px; color: var(--text-muted); line-height: 1.4; }
.tl-bar { height: 4px; border-radius: 2px; margin-top: 6px; background: var(--border); overflow: hidden; }
.tl-bar-fill { height: 100%; border-radius: 2px; transition: width 0.8s cubic-bezier(0.4, 0, 0.2, 1); width: 0%; }
.tl-status {
  display: inline-block; font-size: 9px; font-weight: 600; text-transform: uppercase;
  letter-spacing: 0.04em; padding: 2px 6px; border-radius: 3px; margin-top: 4px;
}

.budget-table { width: 100%; border-collapse: separate; border-spacing: 0; font-size: 12px; }
.budget-table th {
  text-align: left; font-size: 10px; font-weight: 600; color: var(--text-muted);
  text-transform: uppercase; letter-spacing: 0.04em; padding: 8px 12px;
  border-bottom: 1px solid var(--border);
}
.budget-table th:not(:first-child) { text-align: right; }
.budget-table td {
  padding: 10px 12px; border-bottom: 1px solid #1f1f23;
  color: var(--text); transition: all 0.3s;
}
.budget-table td:not(:first-child) {
  text-align: right; font-family: 'SF Mono', 'Fira Code', monospace; font-size: 12px;
}
.budget-table tr {
  opacity: 0; transform: translateY(6px);
  transition: all 0.35s cubic-bezier(0.4, 0, 0.2, 1);
}
.budget-table tr.visible { opacity: 1; transform: translateY(0); }
.budget-table tr.highlight td { background: var(--ring); }
.budget-table tr.dimmed { opacity: 0.2; }
.budget-table .cat-label { display: flex; align-items: center; gap: 8px; }
.cat-dot { width: 8px; height: 8px; border-radius: 2px; flex-shrink: 0; }
.budget-table .row-total td {
  border-top: 2px solid var(--border); font-weight: 700; color: var(--heading);
}
.budget-bar {
  height: 6px; border-radius: 3px; background: var(--bg); margin-top: 4px; overflow: hidden;
}
.budget-bar-fill {
  height: 100%; border-radius: 3px;
  transition: width 0.8s cubic-bezier(0.4, 0, 0.2, 1); width: 0%;
}

.budget-summary {
  display: flex; align-items: center; gap: 24px; margin-top: 16px;
  padding: 14px 16px; background: var(--bg-secondary);
  border: 1px solid var(--border); border-radius: 10px;
  opacity: 0; transform: translateY(6px);
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}
.budget-summary.visible { opacity: 1; transform: translateY(0); }
.budget-ring-container { position: relative; width: 64px; height: 64px; flex-shrink: 0; }
.budget-ring-container svg { width: 64px; height: 64px; transform: rotate(-90deg); }
.budget-ring-label {
  position: absolute; inset: 0; display: flex; align-items: center; justify-content: center;
  font-size: 14px; font-weight: 700; color: var(--heading);
}
.budget-meta { flex: 1; }
.budget-meta-title { font-size: 12px; font-weight: 600; color: var(--heading); margin-bottom: 2px; }
.budget-meta-sub { font-size: 11px; color: var(--text-muted); line-height: 1.4; }

.risk-list { display: flex; flex-direction: column; gap: 10px; }
.risk-card {
  background: var(--bg-secondary); border: 1px solid var(--border);
  border-radius: 8px; padding: 14px 16px;
  opacity: 0; transform: translateY(8px);
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
  display: flex; gap: 12px; align-items: flex-start;
}
.risk-card.visible { opacity: 1; transform: translateY(0); }
.risk-icon {
  width: 28px; height: 28px; border-radius: 6px;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0; font-size: 13px;
}
.risk-icon.high { background: var(--red-dim); color: var(--red); }
.risk-icon.medium { background: var(--yellow-dim); color: var(--yellow); }
.risk-icon.low { background: var(--green-dim); color: var(--green); }
.risk-body { flex: 1; }
.risk-title { font-size: 13px; font-weight: 600; color: var(--heading); margin-bottom: 2px; }
.risk-desc { font-size: 11px; color: var(--text-muted); line-height: 1.4; }
.risk-severity {
  font-size: 9px; font-weight: 600; text-transform: uppercase;
  letter-spacing: 0.04em; padding: 2px 6px; border-radius: 3px;
  margin-top: 6px; display: inline-block;
}
.risk-severity.high { background: var(--red-dim); color: var(--red); }
.risk-severity.medium { background: var(--yellow-dim); color: var(--yellow); }
.risk-severity.low { background: var(--green-dim); color: var(--green); }

slides.script:
var cards = container.querySelectorAll('.kpi-card');
cards.forEach(function(card, i) {
  setTimeout(function() { card.classList.add('visible'); }, 120 + i * 80);
});
var phases = container.querySelectorAll('.tl-phase');
phases.forEach(function(el, i) {
  setTimeout(function() { el.classList.add('visible'); }, 500 + i * 80);
});

var phases = container.querySelectorAll('.tl-phase');
phases.forEach(function(el, i) {
  setTimeout(function() {
    el.classList.add('visible');
    var fill = el.querySelector('.tl-bar-fill');
    if (fill) setTimeout(function() { fill.style.width = fill.getAttribute('data-width') + '%'; }, 200);
  }, 100 + i * 100);
});

var rows = container.querySelectorAll('tbody tr');
rows.forEach(function(tr, i) {
  setTimeout(function() { tr.classList.add('visible'); }, 100 + i * 70);
});

var rows = container.querySelectorAll('tbody tr');
rows.forEach(function(tr, i) {
  setTimeout(function() {
    tr.classList.add('visible');
    var fill = tr.querySelector('.budget-bar-fill');
    if (fill) setTimeout(function() { fill.style.width = fill.getAttribute('data-width') + '%'; }, 150);
  }, 100 + i * 80);
});
var summary = container.querySelector('.budget-summary');
setTimeout(function() {
  summary.classList.add('visible');
  setTimeout(function() {
    var ring = container.querySelector('.spend-ring');
    if (ring) ring.style.transition = 'stroke-dashoffset 1.2s cubic-bezier(0.4,0,0.2,1)';
    if (ring) ring.style.strokeDashoffset = '57.18';
  }, 300);
}, 100 + 5 * 80 + 100);

var cards = container.querySelectorAll('.risk-card');
cards.forEach(function(card, i) {
  setTimeout(function() { card.classList.add('visible'); }, 100 + i * 100);
});
